const Badge = ({s}) => {
  const m = { IN_PROGRESS:{bg:'#1E3A5F',c:C.ac,l:'In Progress',p:1}, PENDING_SIGNATURE:{bg:'#3B2F1A',c:C.wa,l:'Pending Signature',p:1}, NEW:{bg:'#1A2E3B',c:'#60A5FA',l:'New'}, COMPLETE:{bg:'#1A3B2F',c:C.ok,l:'Complete'}, STOPPED:{bg:'#3B1A1A',c:C.no,l:'FICA Failed'}, PASSED:{bg:'#1A3B2F',c:C.ok,l:'Passed'}, FAILED:{bg:'#3B1A1A',c:C.no,l:'Failed'}, PENDING:{bg:'#3B2F1A',c:C.wa,l:'Pending',p:1}, VERIFIED:{bg:'#1A3B2F',c:C.ok,l:'Verified'}, NOT_STARTED:{bg:C.bd,c:C.t2,l:'Not Started'}, AWAITING_CLIENT:{bg:'#3B2F1A',c:C.wa,l:'Awaiting Client',p:1}, IN_REVIEW:{bg:'#1E3A5F',c:C.ac,l:'In Review',p:1}, SIGNED:{bg:'#1A3B2F',c:C.ok,l:'Signed'}, ACTIVE:{bg:'#1A3B2F',c:C.ok,l:'Active'}, EXPIRING:{bg:'#3B2F1A',c:C.wa,l:'Expiring',p:1}, APPROVED:{bg:'#1A3B2F',c:C.ok,l:'Approved'} };
  const v = m[s]||m.NOT_STARTED;
  return <span style={{background:v.bg,color:v.c,padding:'4px 10px',borderRadius:6,fontSize:11,fontFamily:"'Courier New',monospace",fontWeight:600,display:'inline-flex',alignItems:'center',gap:6,whiteSpace:'nowrap'}}>{v.p&&<span style={{width:6,height:6,borderRadius:'50%',background:v.c,animation:'pulse 2s infinite'}}/>}{v.l}</span>;
};
const PBar = ({pct,h=6,color}) => <div style={{background:C.bd,borderRadius:h/2,height:h,width:'100%',overflow:'hidden'}}><div style={{width:`${pct}%`,height:'100%',background:color||(pct===100?C.ok:pct>60?C.ac:pct>30?C.wa:'#60A5FA'),borderRadius:h/2,transition:'width .6s ease'}}/></div>;
const Toast = ({msg,type,onClose}) => { useEffect(()=>{const t=setTimeout(onClose,3000);return()=>clearTimeout(t)},[onClose]); return <div style={{position:'fixed',bottom:24,right:24,background:type==='success'?C.ok:type==='warning'?C.wa:C.no,color:'#fff',padding:'14px 24px',borderRadius:10,fontSize:14,fontWeight:500,zIndex:9999,boxShadow:'0 8px 32px rgba(0,0,0,.4)',animation:'slideUp .3s ease'}}>{msg}</div>; };
const KPI = ({icon,value,label,trend}) => <div style={{background:C.sf,border:`1px solid ${C.bd}`,borderRadius:12,padding:'20px 24px',flex:1,minWidth:170}}><div style={{display:'flex',alignItems:'center',gap:10,marginBottom:8}}><span style={{fontSize:18}}>{icon}</span><span style={{fontSize:11,color:C.t2,textTransform:'uppercase',letterSpacing:1}}>{label}</span></div><div style={{fontSize:32,fontWeight:700,color:C.tx,fontFamily:"Georgia,serif"}}>{value}</div>{trend&&<div style={{fontSize:11,color:trend.includes('↑')||trend.includes('+')?C.ok:trend.includes('↓')?C.no:C.t2,marginTop:4}}>{trend}</div>}</div>;
const Cd = ({children,style:s,...p}) => <div style={{background:C.sf,border:`1px solid ${C.bd}`,borderRadius:12,...s}} {...p}>{children}</div>;
const Hdr = ({title,sub,right}) => <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:24}}><div><div style={{fontFamily:"Georgia,serif",fontSize:22,color:C.tx}}>{title}</div>{sub&&<div style={{fontSize:13,color:C.t2,marginTop:4}}>{sub}</div>}</div>{right}</div>;
const Btn = ({children,primary,danger,onClick,style:s}) => <button onClick={onClick} style={{padding:'10px 20px',background:primary?C.ac:danger?C.no:'transparent',border:primary||danger?'none':`1px solid ${C.b2}`,color:primary||danger?'#fff':C.t2,borderRadius:8,fontSize:13,cursor:'pointer',fontWeight:primary||danger?600:400,...s}}>{children}</button>;
const Fld = ({label,value,select,options,textarea}) => <div><label style={{fontSize:11,color:C.t2,textTransform:'uppercase',letterSpacing:1}}>{label}</label>{select?<select defaultValue={value} style={{width:'100%',padding:'10px 14px',background:C.el,border:`1px solid ${C.bd}`,borderRadius:6,color:C.tx,fontSize:13,marginTop:4}}>{options.map(o=><option key={o}>{o}</option>)}</select>:textarea?<textarea defaultValue={value} style={{width:'100%',height:80,padding:'10px 14px',background:C.el,border:`1px solid ${C.bd}`,borderRadius:6,color:C.tx,fontSize:13,marginTop:4,resize:'vertical'}}/>:<input defaultValue={value} style={{width:'100%',padding:'10px 14px',background:C.el,border:`1px solid ${C.bd}`,borderRadius:6,color:C.tx,fontSize:13,marginTop:4}}/>}</div>;
const SL = ({children,style:s}) => <div style={{fontSize:12,fontWeight:600,color:C.t2,textTransform:'uppercase',letterSpacing:1,marginBottom:16,...s}}>{children}</div>;
const TH = ({children}) => <th style={{padding:'12px 16px',textAlign:'left',color:C.t2,fontSize:10,textTransform:'uppercase',letterSpacing:1,fontWeight:500}}>{children}</th>;
const TD = ({children,mono,accent,style:s}) => <td style={{padding:'12px 16px',color:accent?C.ac:C.tx,...(mono&&{fontFamily:"'Courier New',monospace",fontSize:12}),...s}}>{children}</td>;

